print(f"Written {len(examples)} examples to {output_path}")

# Validate
with open(output_path, "r", encoding="utf-8") as f:
    lines = f.readlines()
    valid = 0
    for i, line in enumerate(lines, 1):
        obj = json.loads(line)
        assert "messages" in obj, f"Line {i}: missing messages"
        assert len(obj["messages"]) >= 2, f"Line {i}: too few messages"
        for m in obj["messages"]:
            assert "role" in m and "content" in m, f"Line {i}: bad message format"
        valid += 1
    print(f"Validation: {valid}/{len(lines)} lines valid")
